import { DefineTypesService } from '@shared/services/define-types.service';
import { DashToCamelcasePipe } from '@shared/pipes/dash-to-camelcase.pipe';
import { Component, Input } from '@angular/core';
import { AbstractControl, FormArray } from '@angular/forms';

@Component({
  selector: 'app-copy-with',
  templateUrl: './copy-with.component.html',
  styleUrls: ['./copy-with.component.sass'],
})
export class CopyWithComponent {
  @Input()
  public fields!: FormArray;
  @Input()
  public className!: string;
  public constructor(
    private _dashUpperCase: DashToCamelcasePipe,
    private _defineTypeService: DefineTypesService
  ) {}
  public getField(field: AbstractControl): string {
    return this._defineTypeService.getTypeProperty(field);
  }
  public comma(index: number): string {
    return index === this.fields.length - 1 ? '' : ',';
  }
  public getCopyWithField(field: AbstractControl): string {
    const { property } = field.value;
    const normalizedProperty: string = this._dashUpperCase.transform(property);
    return `${normalizedProperty}: ${normalizedProperty} ?? this.${normalizedProperty}`;
  }
}
