import { Component, OnInit } from '@angular/core';
import {
  AbstractControl,
  FormArray,
  FormControl,
  FormGroup,
} from '@angular/forms';
import { Type } from '@shared/enums/types.enum';
import { DashToCamelcasePipe } from '@shared/pipes/dash-to-camelcase.pipe';
import { FirstLetterUppercasePipe } from '@shared/pipes/first-letter-uppercase.pipe';
import { DefineTypesService } from '@shared/services/define-types.service';

@Component({
  selector: 'app-class-generator',
  templateUrl: './class-generator.component.html',
  styleUrls: ['./class-generator.component.sass'],
})
export class ClassGeneratorComponent implements OnInit {
  public fields: FormArray = new FormArray([]);
  public className: FormControl = new FormControl('');
  public needFromJson: FormControl = new FormControl(false);
  public needCopyWith: FormControl = new FormControl(false);
  public needToJson: FormControl = new FormControl(false);
  public json: FormControl = new FormControl();
  public error: string = '';
  public fromJsonString: FormControl = new FormControl(false);

  public constructor(
    private _upperCase: FirstLetterUppercasePipe,
    private _dashUpperCase: DashToCamelcasePipe,
    private _defineTypeService: DefineTypesService
  ) {}
  public ngOnInit(): void {
    this.className.valueChanges.subscribe((value: string) => {
      this.className.patchValue(this._upperCase.transform(value), {
        emitEvent: false,
      });
    });

    this.json.valueChanges.subscribe((value: string) => {
      try {
        this.fields = new FormArray([]);
        const obj: { [key: string]: string } = JSON.parse(value);
        for (const key in obj) {
          this.defineAndAddType(obj[key], key);
        }
        this.error = '';
      } catch (e) {
        this.error = 'Incorrect json';
        this.fields = new FormArray([]);
      }
    });
  }

  public defineAndAddType(str: string, prop: string): void {
    const isList: boolean = this._defineTypeService.isArray(str);
    const value: string =
      (this._defineTypeService.isArray(str) && str[0]) || str;
    if (this._defineTypeService.isNull(value)) {
      this.addField(prop, Type.String, isList);
      return;
    }
    if (this._defineTypeService.isDouble(value)) {
      this.addField(prop, Type.double, isList);
      return;
    }
    if (this._defineTypeService.isInt(value)) {
      this.addField(prop, Type.int, isList);
      return;
    }
    if (this._defineTypeService.isString(value)) {
      this.addField(prop, Type.String, isList);
      return;
    }
    if (this._defineTypeService.isDate(value)) {
      this.addField(prop, Type.DateTime, isList);
      return;
    }

    if (this._defineTypeService.isObject(value)) {
      this.addField(prop.toLowerCase(), Type.custom, isList, prop);
    }
  }

  public getClassConstructor(): string {
    const constructor: string = this.fields?.controls
      .map((field: FormGroup, index: number) => {
        const { property } = field.value;
        const comma: string = index !== this.fields.length - 1 ? ',' : '';
        return `this.${this._dashUpperCase.transform(property)}${comma}`;
      })
      .join('');
    return `${this.className.value}({${constructor}});`;
  }

  public changeIsList(index: number): void {
    this.fields.controls[index].patchValue({ isList: false });
  }

  public getField(field: AbstractControl): string {
    return this._defineTypeService.getTypeProperty(field);
  }

  public removeItem(index: number): void {
    this.fields.removeAt(index);
  }

  public removeEnum({
    field,
    index,
  }: {
    field: AbstractControl;
    index: number;
  }): void {
    (field.get('enumValues') as FormArray).removeAt(index);
  }

  public addField(
    property: string = '',
    type: Type = Type.int,
    isList: boolean = false,
    model: string = ''
  ): void {
    this.fields.push(
      new FormGroup({
        isList: new FormControl(isList),
        enumValues: new FormArray([]),
        property: new FormControl(property),
        type: new FormControl(type),
        modelName: new FormControl(model), // custom/enum name
      })
    );
  }

  public addEnum(field: FormGroup): void {
    (field.get('enumValues') as FormArray)?.push(this.createEnum());
  }

  public createEnum(): FormGroup {
    return new FormGroup({
      json: new FormControl(''),
      name: new FormControl(''),
    });
  }
}
