import { FirstLetterUppercasePipe } from './../shared/pipes/first-letter-uppercase.pipe';
import { AbstractControl, FormArray } from '@angular/forms';
import { Component, Input } from '@angular/core';
import { DashToCamelcasePipe } from '@shared/pipes/dash-to-camelcase.pipe';
import { Type } from '@shared/enums/types.enum';

@Component({
  selector: 'app-to-json',
  templateUrl: './to-json.component.html',
  styleUrls: ['./to-json.component.sass'],
})
export class ToJsonComponent {
  @Input()
  public fields!: FormArray;
  @Input()
  public className!: string;
  public needToString: Type[] = [Type.DateTime, Type.double];

  public constructor(
    private _dashUpperCase: DashToCamelcasePipe,
    private _firstLetterUpperCase: FirstLetterUppercasePipe
  ) {}

  public comma(index: number): string {
    return index === this.fields.length - 1 ? '' : ',';
  }

  public getToJson(field: AbstractControl): string {
    const { modelName, type, property, isList } = field.value;
    const normalizedProperty: string = this._dashUpperCase.transform(property);
    if (type === Type.enum) {
      return this.getFieldToJson(normalizedProperty, this.parseEnum(property));
    }
    if (type === Type.custom) {
      return this.getFieldToJson(
        normalizedProperty,
        this.parseCustom(modelName, normalizedProperty, isList)
      );
    }
    return this.getFieldToJson(
      normalizedProperty,
      this.parseDefault(type, normalizedProperty, isList)
    );
  }

  public parseEnum(property: string): string {
    return `getJsonFrom${this._firstLetterUpperCase.transform(property)}()`;
  }

  public parseDefault(type: Type, property: string, isList: boolean): string {
    if (isList) {
      return this.getListWrap(property, type);
    }
    if (this.needToString.includes(type as Type)) {
      return `${property}.toString()`;
    }
    return property;
  }

  public parseCustom(model: string, property: string, isList: boolean): string {
    if (isList) {
      return this.getListWrap(property, model, true);
    }
    return `${property}.toJson()`;
  }

  public getListWrap(
    property: string,
    type: string | Type,
    isCustom: boolean = false
  ): string {
    if (isCustom) {
      return `${property}.map((${type} value) => value.toJson()).toList()`;
    }
    if (this.needToString.includes(type as Type)) {
      return `${property}.map((${type} value) => value.toString()).toList()`;
    }
    return property;
  }

  public getFieldToJson(left: string, middle: string): string {
    return `'${left}': ${middle}`;
  }
}
