import { ParseTypePipe } from './../shared/pipes/parse-type.pipe';
import { FirstLetterUppercasePipe } from './../shared/pipes/first-letter-uppercase.pipe';
import { AbstractControl, FormArray } from '@angular/forms';
import { Component, Input } from '@angular/core';
import { Type } from '@shared/enums/types.enum';
import { DashToCamelcasePipe } from '@shared/pipes/dash-to-camelcase.pipe';

@Component({
  selector: 'app-from-json',
  templateUrl: './from-json.component.html',
  styleUrls: ['./from-json.component.sass'],
})
export class FromJsonComponent {
  @Input()
  public fields!: FormArray;
  @Input()
  public className!: string;
  public needCheckOnNull: Type[] = [Type.custom, Type.DateTime, Type.double];
  public constructor(
    private _dashUpperCase: DashToCamelcasePipe,
    private _firstLetterUppercase: FirstLetterUppercasePipe,
    private _parseType: ParseTypePipe
  ) {}

  public comma(index: number): string {
    return index === this.fields.length - 1 ? '' : ',';
  }

  public getFromJson(field: AbstractControl): string {
    const { property, isList, type, modelName } = field.value;
    const normalizedType: string = `${this._dashUpperCase.transform(property)}`;
    if (type === Type.enum) {
      return this.getFieldFromJson(normalizedType, this.parseEnum(field));
    }
    if (type === Type.custom) {
      return this.getFieldFromJson(
        normalizedType,
        this.parseCustom(modelName, property, isList)
      );
    }
    return this.getFieldFromJson(
      normalizedType,
      this.parsePrimitiveTypes(type, property, isList)
    );
  }

  public parseEnum(field: AbstractControl): string {
    const { property, enumValues } = field.value;
    const type: string = this._parseType.transform(enumValues[0]?.json);
    return `get${this._firstLetterUppercase.transform(
      property
    )}FromJson(${this.parsePrimitiveTypes(type as Type, property, false)})`;
  }

  public parseCustom(
    modelName: string,
    property: string,
    isList: boolean
  ): string {
    const parsed: string = `${modelName}.fromJson(json['${property}'] as Map<String,dynamic>)`;
    if (isList) {
      return this.typeCastList(property, modelName, parsed);
    }
    return parsed;
  }

  public parsePrimitiveTypes(
    type: Type,
    property: string,
    isList: boolean
  ): string {
    let parsed: string = `json['${property}'] as ${type}`;
    if (this.needCheckOnNull.includes(type)) {
      parsed = this.jsonNotEqualNull(this.typeCast(type, parsed), property);
    }
    if (isList) {
      return this.typeCastList(property, type, parsed);
    }
    return parsed;
  }

  public jsonNotEqualNull(ifNotNull: string, property: string): string {
    return `json['${property}'] !=null ? ${ifNotNull} : null`;
  }

  public typeCast(type: string, parsed: string): string {
    return `${type}.parse(${parsed})`;
  }

  public typeCastList(property: string, type: string, parsed: string): string {
    return `json[${property}] !=null ? json[${property}].map<${type}>((dynamic item)=> ${parsed}) as List<${type}> : <${type}>[]`;
  }

  public getFieldFromJson(left: string, middle: string): string {
    return `${left}: ${middle}`;
  }
}
