import { FirstLetterUppercasePipe } from './../shared/pipes/first-letter-uppercase.pipe';
import { ParseTypePipe } from './../shared/pipes/parse-type.pipe';
import { Component, Input } from '@angular/core';
import { AbstractControl, FormArray, FormGroup } from '@angular/forms';

@Component({
  selector: 'app-from-to-enum',
  templateUrl: './from-to-enum.component.html',
  styleUrls: ['./from-to-enum.component.sass'],
})
export class FromToEnumComponent {
  @Input()
  public fields!: FormArray;
  public constructor(
    private _parseType: ParseTypePipe,
    private _firstLetterUppercase: FirstLetterUppercasePipe
  ) {}
  public getEnumType(item: AbstractControl): string {
    if (!(item.get('enumValues') as FormArray)?.controls[0]) {
      return '';
    }
    return (
      (item.get('enumValues') as FormArray)?.controls[0].get('json')?.value ??
      ''
    );
  }
  public isString(str: string): boolean {
    return this._parseType.transform(str) === 'String';
  }
  public getEnumArray(item: AbstractControl): FormGroup[] {
    return (item.get('enumValues') as FormArray)?.controls as FormGroup[];
  }
  public getNamingEnum(item: AbstractControl): string {
    return `${this._parseType.transform(
      this.getEnumType(item)
    )} getJsonFrom${this._firstLetterUppercase.transform(
      item.get('field')?.value
    )} (){`;
  }

  public getNamingFromJson(item: AbstractControl): string {
    return `static ${
      item.get('model')?.value
    } get${this._firstLetterUppercase.transform(
      item.get('field')?.value
    )}FromJson(${this._parseType.transform(this.getEnumType(item))} json){`;
  }
  public getCase(item: AbstractControl, enumItem: AbstractControl): string {
    return `case ${item.get('model')?.value}.${enumItem.get('name')?.value}:`;
  }
  public getCaseFromJson(enumItem: AbstractControl): string {
    const quote: string = this.isString(enumItem.get('json')?.value) ? `'` : '';
    return `case ${quote}${enumItem.get('json')?.value}${quote}:`;
  }
  public getCaseReturn(enumItem: AbstractControl): string {
    const quote: string = this.isString(enumItem.get('json')?.value) ? `'` : '';
    return `return ${quote}${enumItem.get('json')?.value}${quote};`;
  }
  public getCaseFromJsonReturn(
    item: AbstractControl,
    enumItem: AbstractControl
  ): string {
    return `return ${item.get('model')?.value}.${enumItem.get('name')?.value};`;
  }
}
