import { Component, Input } from '@angular/core';
import { FormGroup, FormArray, AbstractControl } from '@angular/forms';
import { Type } from '@shared/enums/types.enum';

@Component({
  selector: 'app-enum',
  templateUrl: './enum.component.html',
  styleUrls: ['./enum.component.sass'],
})
export class EnumComponent {
  @Input()
  public fields!: FormArray;
  @Input()
  public className!: string;

  public getEnumFields(): FormGroup[] {
    const enums: FormGroup[] = this.fields.controls.filter(
      (field: FormGroup) => (field.get('type')?.value as Type) === Type.enum
    ) as FormGroup[];
    return enums;
  }

  public getEnumKeys(field: AbstractControl): string {
    const enumValues: FormGroup[] = (field.get('enumValues') as FormArray)
      ?.controls as FormGroup[];
    return enumValues
      ?.map((enumFg: FormGroup, index: number) => {
        const { name } = enumFg.value;
        const comma: string = enumValues.length - 1 === index ? '' : ',';
        return `${name}${comma}`;
      })
      .join('');
  }
}
