import { AbstractControl, FormGroup } from '@angular/forms';
import { Pipe, PipeTransform } from '@angular/core';
@Pipe({
  name: 'transormToFormGroup',
})
export class TransformToFormGroupPipe implements PipeTransform {
  // tslint:disable-next-line: no-any
  public transform(value: AbstractControl, nestedControl: string = ''): any {
    if (nestedControl) {
      return (value.get('enumValues') as FormGroup)?.controls;
    }
    return value as FormGroup;
  }
}
