import { AbstractControl, FormGroup } from '@angular/forms';
import { Component, EventEmitter, Input, Output, OnInit } from '@angular/core';
import { Type } from '@shared/enums/types.enum';
@Component({
  selector: 'app-field',
  templateUrl: './field.component.html',
  styleUrls: ['./field.component.sass'],
})
export class FieldComponent implements OnInit {
  @Input() public field!: FormGroup;
  @Output()
  public removeItem: EventEmitter<void> = new EventEmitter<void>();
  @Output()
  public addEnum: EventEmitter<FormGroup> = new EventEmitter<FormGroup>();
  @Output()
  public changeType: EventEmitter<void> = new EventEmitter<void>();
  @Output()
  public removeEnum: EventEmitter<{
    field: FormGroup;
    index: number;
  }> = new EventEmitter<{ field: FormGroup; index: number }>();

  public types: Type[] = [
    Type.int,
    Type.double,
    Type.custom,
    Type.DateTime,
    Type.String,
    Type.enum,
    Type.bool,
  ];
  public ngOnInit(): void {
    (this.field.get('type') as AbstractControl).valueChanges.subscribe(() => {
      this.changeType.emit();
    });
  }
}
