import { Pipe, PipeTransform } from '@angular/core';

@Pipe({
  name: 'dashToCamelcase',
})
export class DashToCamelcasePipe implements PipeTransform {
  public transform(value: string): string {
    if (value) {
      const valueArray: string[] = value.replace('_', '-').split('-');
      if (value.length > 1) {
        value = valueArray
          .map((item: string, index: number) =>
            index !== 0
              ? item && item[0].toUpperCase() + item.slice(1)
              : item[0].toLowerCase() + item.slice(1)
          )
          .join('');
      }
    }
    return value;
  }
}
