import { AbstractControl } from '@angular/forms';
import { Injectable } from '@angular/core';
import { JsType } from '@shared/enums/js-types.enum';
import { Type } from '@shared/enums/types.enum';
import { DashToCamelcasePipe } from '@shared/pipes/dash-to-camelcase.pipe';

@Injectable({
  providedIn: 'root',
})
export class DefineTypesService {
  public constructor(private _dashUpperCase: DashToCamelcasePipe) {}
  public getTypeProperty(field: AbstractControl): string {
    const { type, property, modelName, isList } = field.value;
    const normalizedProperty: string = this._dashUpperCase.transform(property);
    const typeModel: string = this.isDefault(type) ? type : modelName;
    const strStart: string = isList ? `List<${typeModel}>` : typeModel;
    return `${strStart} ${normalizedProperty}`;
  }
  public isDefault(value: Type): boolean {
    return value !== Type.custom && value !== Type.enum;
  }
  public isDate(value: string): boolean {
    return !!new Date(value).getMonth();
  }
  public isNull(value: string): boolean {
    return value === null;
  }
  public isString(value: string): boolean {
    return typeof value === JsType.string;
  }
  public isInt(value: string): boolean {
    return !!(Number(value) && Number(value) % 1 === 0);
  }
  public isObject(value: string): boolean {
    return typeof value === JsType.object;
  }
  public isDouble(value: string): boolean {
    return !!(Number(value) && Number(value) % 1 !== 0);
  }
  public isArray(value: string): boolean {
    return Array.isArray(value);
  }
}
