import { Pipe, PipeTransform } from '@angular/core';

@Pipe({
  name: 'parseType',
})
export class ParseTypePipe implements PipeTransform {
  public transform(value: string): string {
    if (!isNaN(parseInt(value))) {
      return 'int';
    }
    if (typeof value === 'string') {
      return 'String';
    }
    return '';
  }
}
